/**
 * Core rendering logic for the SVGSketch GitHub Action.
 *
 * Pure: takes an input string + options, returns a rendered result +
 * diagnostics. No filesystem, no logging — those live at the edges so
 * this module can be exercised by unit tests.
 */

import {
  parseDocument,
  renderToSvg,
  substituteVariables,
  validateSnapshot,
  type HistorySnapshot,
  type VariableMap,
  type ValidationError,
  type RenderOptions,
} from '@svgsketch/core';

/**
 * Options accepted by {@link renderSvgsContent}.
 */
export interface RenderSvgsOptions {
  /** Template variable overrides merged over document defaults. */
  variables?: VariableMap;
  /** Explicit width override. */
  width?: number;
  /** Explicit height override. */
  height?: number;
  /** Background color (emits a background `<rect>`). */
  background?: string;
}

/**
 * Result of rendering one `.svgs` document.
 */
export interface RenderResult {
  /** The rendered SVG string. */
  svg: string;
  /** The parsed + migrated + substituted snapshot (for post-hoc inspection). */
  snapshot: HistorySnapshot;
  /** Validation errors surfaced during parse. Empty on success. */
  errors: ValidationError[];
  /** Validation warnings surfaced during parse. May be non-empty on success. */
  warnings: ValidationError[];
}

/**
 * Render a `.svgs` document string to SVG.
 *
 * Pipeline: `parseDocument` (validates + migrates) → `substituteVariables`
 * (merges defaults + overrides) → `renderToSvg`. Validation warnings are
 * collected and returned separately from errors so the caller can decide
 * whether to fail the run (the `fail-on-warnings` input).
 *
 * @param content  - Raw `.svgs` file content.
 * @param options  - Overrides for variables, dimensions, background.
 * @returns The rendered SVG plus diagnostics.
 * @throws If the document cannot be parsed or fails validation errors.
 */
export function renderSvgsContent(content: string, options: RenderSvgsOptions = {}): RenderResult {
  // parseDocument validates + migrates. It throws on invalid JSON or
  // validation errors — caller converts that to a core.setFailed() call.
  const parsed = parseDocument(content);

  // Re-run validation to harvest warnings (parseDocument only throws on
  // errors; warnings are surfaced through validateSnapshot directly).
  const result = validateSnapshot(parsed);

  // Apply variable substitution — defaults always run, overrides merge on top.
  const substituted = substituteVariables(parsed, options.variables ?? {});

  const renderOpts: RenderOptions = {
    width: options.width,
    height: options.height,
    backgroundColor: options.background,
  };

  const svg = renderToSvg(substituted, renderOpts);

  return {
    svg,
    snapshot: substituted,
    errors: result.errors,
    warnings: result.warnings,
  };
}

/**
 * Compute the SVG output path for a given `.svgs` input path.
 *
 * - When `outputDir` is `null`, the output sits next to the source
 *   (`foo/bar.svgs` → `foo/bar.svg`).
 * - When `outputDir` is set, the source path's directory tree is mirrored
 *   beneath `outputDir` relative to `baseDir`
 *   (`designs/icons/a.svgs` → `outputDir/icons/a.svg` when `baseDir` is `designs`).
 *
 * The `baseDir` anchor lets callers strip a common prefix so that
 * `output-dir: rendered` doesn't recreate the full workspace path.
 *
 * All paths are treated as POSIX-style strings; callers should have
 * already normalized separators (`@actions/glob` emits forward slashes
 * on all platforms).
 */
export function computeOutputPath(
  sourcePath: string,
  outputDir: string | null,
  baseDir: string
): string {
  const svgPath = sourcePath.replace(/\.svgs$/i, '.svg');
  if (outputDir === null) return svgPath;

  // Strip the baseDir prefix if present; otherwise use the source path
  // unchanged (minus any drive letter / leading slash).
  const normalizedBase = baseDir.replace(/[\\/]+$/, '');
  let relative = svgPath;
  if (normalizedBase && svgPath.startsWith(normalizedBase + '/')) {
    relative = svgPath.slice(normalizedBase.length + 1);
  } else if (svgPath.startsWith('/')) {
    relative = svgPath.slice(1);
  }

  const normalizedOut = outputDir.replace(/[\\/]+$/, '');
  return `${normalizedOut}/${relative}`;
}
