/**
 * Input parsing for the SVGSketch GitHub Action.
 *
 * These functions are pure (no `@actions/core` calls, no filesystem) so
 * they can be unit-tested without mocking the Actions runtime.
 */

import type { VariableMap } from '@svgsketch/core';
import { parseVariableArgs } from '@svgsketch/core';

/**
 * How renders are embedded in a PR comment when `commentOnPr` is enabled.
 * - `png`: rasterize each SVG to a base64-encoded PNG embedded inline
 *   via a data URI. Works within GitHub's CSP for comment markdown.
 * - `artifact-link`: skip rasterization, post a link to the uploaded
 *   artifact only. Useful when renders are too large for inline embed.
 */
export type CommentFormat = 'png' | 'artifact-link';

/**
 * Parsed, validated Action inputs — consumed by the runner.
 */
export interface ActionInputs {
  /** Glob pattern (or literal path) for `.svgs` files to render. */
  input: string;
  /** Directory to write outputs into, or `null` to write next to sources. */
  outputDir: string | null;
  /** Template variable overrides (merged on top of document defaults). */
  variables: VariableMap;
  /** Explicit render width, or undefined to use document default. */
  width: number | undefined;
  /** Explicit render height, or undefined to use document default. */
  height: number | undefined;
  /** Background color string, or undefined for no background. */
  background: string | undefined;
  /** When true, validation warnings abort the run. */
  failOnWarnings: boolean;
  /** Post/update a PR comment with rendered previews. */
  commentOnPr: boolean;
  /** Embed format for the PR comment (see {@link CommentFormat}). */
  commentFormat: CommentFormat;
  /** Per-image size cap (KB) before falling back to artifact-link mode. */
  commentMaxKb: number;
  /** Token used to author the PR comment. */
  githubToken: string;
}

/**
 * Parse the `variables` input. Accepts:
 *   - An empty string (→ `{}`)
 *   - A JSON object (→ parsed directly, values coerced to strings)
 *   - Newline-separated `KEY=VALUE` pairs
 *
 * The two formats are distinguished by the first non-whitespace character —
 * `{` indicates JSON. This mirrors what a typical user would type in a
 * multi-line workflow string without needing to escape quotes.
 */
export function parseVariables(raw: string): VariableMap {
  const trimmed = raw.trim();
  if (trimmed === '') return {};

  // Recognize both `{` and `[` as JSON — users who write an array meant
  // JSON (even if we reject it), and dispatching it as KEY=VALUE would
  // produce a confusing "invalid line" error.
  if (trimmed.startsWith('{') || trimmed.startsWith('[')) {
    let parsed: unknown;
    try {
      parsed = JSON.parse(trimmed);
    } catch (err) {
      throw new Error(
        `Invalid JSON in 'variables' input: ${(err as Error).message}`
      );
    }
    if (parsed === null || typeof parsed !== 'object' || Array.isArray(parsed)) {
      throw new Error(
        `'variables' JSON must be an object (got ${Array.isArray(parsed) ? 'array' : typeof parsed}).`
      );
    }
    const out: VariableMap = {};
    for (const [k, v] of Object.entries(parsed as Record<string, unknown>)) {
      // Coerce to string — core's substituteVariables handles numeric coercion
      // from its end based on the target property.
      out[k] = v === null || v === undefined ? '' : String(v);
    }
    return out;
  }

  // KEY=VALUE lines — pass through the core's existing parser so behavior
  // matches `svgsketch render --var` exactly.
  const lines = trimmed
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter((line) => line.length > 0 && !line.startsWith('#'));
  if (lines.length === 0) return {};
  return parseVariableArgs(lines);
}

/**
 * Parse a numeric input (width/height). Empty strings map to `undefined`.
 * Rejects trailing garbage (e.g. `"100px"`) to match the CLI's strictness.
 */
export function parseNumericInput(raw: string, fieldName: string): number | undefined {
  const trimmed = raw.trim();
  if (trimmed === '') return undefined;
  if (!/^[+-]?(?:\d+\.?\d*|\.\d+)$/.test(trimmed)) {
    throw new Error(`Invalid '${fieldName}' input: "${raw}" is not a valid number.`);
  }
  const n = Number(trimmed);
  if (!Number.isFinite(n) || n <= 0) {
    throw new Error(`Invalid '${fieldName}' input: must be a positive finite number.`);
  }
  return n;
}

/**
 * Parse a boolean input. Accepts `true`/`false` (case-insensitive) and
 * empty string (→ default). Anything else throws.
 */
export function parseBooleanInput(raw: string, fieldName: string, defaultValue: boolean): boolean {
  const trimmed = raw.trim().toLowerCase();
  if (trimmed === '') return defaultValue;
  if (trimmed === 'true') return true;
  if (trimmed === 'false') return false;
  throw new Error(`Invalid '${fieldName}' input: expected 'true' or 'false', got "${raw}".`);
}

/**
 * Parse a string input, returning `undefined` for empty strings so the
 * caller can distinguish "not provided" from "empty value."
 */
export function parseOptionalString(raw: string): string | undefined {
  const trimmed = raw.trim();
  return trimmed === '' ? undefined : trimmed;
}

/**
 * Lookup type compatible with `@actions/core`'s `getInput`. Taking a
 * function here (rather than importing core directly) keeps this module
 * testable in isolation — tests inject a map, production injects
 * `@actions/core`'s real getter.
 */
export type InputGetter = (name: string) => string;

/**
 * Parse the `comment-format` input. Rejects unknown values so a typo
 * ("pngs", "link") surfaces as a clear error rather than silently
 * falling back to a default.
 */
export function parseCommentFormat(raw: string): CommentFormat {
  const trimmed = raw.trim().toLowerCase();
  if (trimmed === '' || trimmed === 'png') return 'png';
  if (trimmed === 'artifact-link') return 'artifact-link';
  throw new Error(
    `Invalid 'comment-format' input: expected 'png' or 'artifact-link', got "${raw}".`
  );
}

/**
 * Parse a positive-integer input (e.g. `comment-max-kb`). Empty strings
 * fall back to `defaultValue`. Non-integers, negatives, and zero all
 * throw.
 */
export function parsePositiveIntInput(
  raw: string,
  fieldName: string,
  defaultValue: number
): number {
  const trimmed = raw.trim();
  if (trimmed === '') return defaultValue;
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(
      `Invalid '${fieldName}' input: "${raw}" is not a positive integer.`
    );
  }
  const n = Number(trimmed);
  if (!Number.isFinite(n) || n <= 0) {
    throw new Error(`Invalid '${fieldName}' input: must be a positive integer.`);
  }
  return n;
}

/**
 * Parse all Action inputs into a validated `ActionInputs` object. Throws
 * a single `Error` on the first invalid field so the caller can report
 * it via `core.setFailed` with a clear message.
 */
export function parseInputs(getInput: InputGetter): ActionInputs {
  const input = getInput('input').trim() || '**/*.svgs';
  const outputDirRaw = getInput('output-dir').trim();
  const variables = parseVariables(getInput('variables'));
  const width = parseNumericInput(getInput('width'), 'width');
  const height = parseNumericInput(getInput('height'), 'height');
  const background = parseOptionalString(getInput('background'));
  const failOnWarnings = parseBooleanInput(
    getInput('fail-on-warnings'),
    'fail-on-warnings',
    false
  );
  const commentOnPr = parseBooleanInput(
    getInput('comment-on-pr'),
    'comment-on-pr',
    false
  );
  const commentFormat = parseCommentFormat(getInput('comment-format'));
  const commentMaxKb = parsePositiveIntInput(
    getInput('comment-max-kb'),
    'comment-max-kb',
    400
  );
  const githubToken = getInput('github-token').trim();

  return {
    input,
    outputDir: outputDirRaw === '' ? null : outputDirRaw,
    variables,
    width,
    height,
    background,
    failOnWarnings,
    commentOnPr,
    commentFormat,
    commentMaxKb,
    githubToken,
  };
}
