/**
 * PR comment rendering — rasterizes each generated SVG to a PNG, embeds
 * the PNGs inline via base64 data URIs, and posts (or updates) a single
 * comment on the triggering pull request.
 *
 * ## Why PNG, not SVG
 *
 * GitHub's Content Security Policy blocks `data:image/svg+xml;base64,…`
 * in rendered markdown. `data:image/png;base64,…` is allowed. Hosting
 * the SVG externally (via artifact, release asset, or gist) also works
 * but adds round-trips and pollutes the repo. Inline PNG is the only
 * self-contained path that renders reliably in PR comments today.
 *
 * ## Comment re-use
 *
 * A single marker (`COMMENT_MARKER`) is written into every comment this
 * action posts. On subsequent runs, the action finds the existing
 * marker-bearing comment and PATCHes it instead of posting a new one —
 * so a noisy PR never accumulates stale render previews.
 */

import * as core from '@actions/core';
import * as github from '@actions/github';
import { readFile } from 'node:fs/promises';
import { dirname, join } from 'node:path';
import { Resvg, initWasm } from '@resvg/resvg-wasm';

/** Hidden HTML marker used to find the comment we own on re-runs. */
export const COMMENT_MARKER = '<!-- svgsketch-render-preview -->';

/**
 * One rendered output to embed in the PR comment. The caller supplies
 * the source path, relative output path, and SVG bytes; rasterization
 * happens inside {@link renderCommentBody}.
 */
export interface RenderedPreview {
  /** Relative path of the source `.svgs` file (for display). */
  sourcePath: string;
  /** Relative path of the rendered SVG (for display). */
  outputPath: string;
  /** The rendered SVG markup. */
  svg: string;
  /** Shape count from the snapshot (for the subline). */
  shapeCount: number;
}

/**
 * Initialize the resvg WASM module exactly once per process.
 *
 * WASM-based rasterization is platform-agnostic (works on Linux, macOS,
 * Windows, and ARM runners without platform-specific binaries) — a
 * native `@resvg/resvg-js` build would only ship the binary for the OS
 * that built the bundle, breaking cross-platform consumers.
 *
 * The `.wasm` file is shipped alongside the bundled `index.js` by ncc;
 * we read it from disk and hand it to `initWasm`. Cached via a module
 * singleton so parallel calls collapse to one init.
 */
let wasmInitPromise: Promise<void> | null = null;
function ensureWasmInitialized(): Promise<void> {
  if (wasmInitPromise) return wasmInitPromise;
  wasmInitPromise = (async () => {
    // The `.wasm` file is copied into `dist/` by our build script so it
    // lives next to the bundled `index.js` at runtime. Look there first
    // (the post-ncc layout); fall back to `require.resolve` for local
    // dev and unit tests, where the bundle doesn't exist yet.
    const candidates = [
      join(dirname(__filename), 'index_bg.wasm'),
    ];
    try {
      // eslint-disable-next-line @typescript-eslint/no-require-imports
      const pkgEntry: string = require.resolve('@resvg/resvg-wasm');
      candidates.push(join(dirname(pkgEntry), 'index_bg.wasm'));
    } catch {
      // No installed package available — will rely on the first candidate.
    }
    let wasmBuffer: Buffer | null = null;
    let lastErr: unknown = null;
    for (const path of candidates) {
      try {
        wasmBuffer = await readFile(path);
        break;
      } catch (err) {
        lastErr = err;
      }
    }
    if (!wasmBuffer) {
      throw new Error(
        `Failed to locate index_bg.wasm for resvg rasterization. Tried: ${candidates.join(
          ', '
        )}. Last error: ${(lastErr as Error)?.message}`
      );
    }
    await initWasm(wasmBuffer);
  })();
  return wasmInitPromise;
}

/**
 * Rasterize an SVG string to PNG bytes.
 *
 * Exported for unit testing. Uses `@resvg/resvg-wasm`, so no native
 * binaries need to ship with the action.
 *
 * @throws If the SVG cannot be parsed. The caller should skip the file
 *   and fall back to an artifact-link style entry rather than failing
 *   the whole run.
 */
export async function rasterizeSvgToPng(svg: string): Promise<Buffer> {
  await ensureWasmInitialized();
  const resvg = new Resvg(svg, {
    fitTo: { mode: 'original' },
    background: 'rgba(0,0,0,0)',
  });
  const pngData = resvg.render();
  return Buffer.from(pngData.asPng());
}

/**
 * Options for constructing the comment body.
 */
export interface BuildCommentBodyOptions {
  /** Rendered previews to embed. */
  previews: RenderedPreview[];
  /** Per-image size cap (bytes) before falling back to artifact note. */
  maxBytesPerImage: number;
  /** Either 'png' (rasterize + embed) or 'artifact-link' (skip embed). */
  format: 'png' | 'artifact-link';
  /** Commit SHA that produced these renders (for traceability). */
  commitSha: string | undefined;
  /** Owner/repo for building the commit link, e.g. `svgsketch/render-action`. */
  repoSlug: string | undefined;
  /** Optional URL of the workflow run (appended to the footer). */
  runUrl: string | undefined;
}

/**
 * Build the markdown body of the preview comment. Splits the heavy
 * string-building out of the I/O path so tests can cover formatting
 * without hitting the network.
 *
 * Async because rasterization (WASM-backed) is async. Callers that only
 * want `artifact-link` mode still await this, but the per-preview path
 * skips resvg entirely in that mode.
 */
export async function buildCommentBody(opts: BuildCommentBodyOptions): Promise<string> {
  const { previews, maxBytesPerImage, format, commitSha, repoSlug, runUrl } = opts;

  const lines: string[] = [];
  lines.push(COMMENT_MARKER);
  lines.push('## 🎨 SVGSketch Render Preview');
  lines.push('');

  // Header line: commit link + file count.
  const fileCountLabel = `**${previews.length}** file${previews.length === 1 ? '' : 's'} rendered`;
  if (commitSha && repoSlug) {
    const short = commitSha.slice(0, 7);
    lines.push(`${fileCountLabel} from commit [\`${short}\`](https://github.com/${repoSlug}/commit/${commitSha}).`);
  } else {
    lines.push(`${fileCountLabel}.`);
  }
  lines.push('');

  for (const p of previews) {
    lines.push(`### \`${p.sourcePath}\``);
    lines.push(`<sub>${p.shapeCount} shape${p.shapeCount === 1 ? '' : 's'} → \`${p.outputPath}\`</sub>`);
    lines.push('');

    if (format === 'artifact-link') {
      lines.push(
        '_Embedded preview disabled (`comment-format: artifact-link`). Download the workflow artifact to view the rendered SVG._'
      );
      lines.push('');
      continue;
    }

    try {
      const png = await rasterizeSvgToPng(p.svg);
      if (png.byteLength > maxBytesPerImage) {
        lines.push(
          `_Rendered PNG is ${(png.byteLength / 1024).toFixed(0)} KB — above the ${(maxBytesPerImage / 1024).toFixed(0)} KB inline-embed limit. Download the workflow artifact to view this file._`
        );
        lines.push('');
        continue;
      }
      const base64 = png.toString('base64');
      lines.push(`![${p.sourcePath}](data:image/png;base64,${base64})`);
      lines.push('');
    } catch (err) {
      lines.push(`_Rasterization failed: ${(err as Error).message}. Download the workflow artifact to view the rendered SVG._`);
      lines.push('');
    }
  }

  // Footer.
  const footerParts: string[] = [];
  footerParts.push('Generated by [`svgsketch/render-action`](https://github.com/svgsketch/render-action)');
  if (runUrl) footerParts.push(`· [workflow run](${runUrl})`);
  lines.push('---');
  lines.push(`<sub>${footerParts.join(' ')}</sub>`);

  return lines.join('\n');
}

/**
 * Runtime context required to locate the PR and authenticate. Built
 * from `github.context` at the edge and passed in so tests can stub.
 */
export interface CommentContext {
  /** `${owner}/${repo}`. */
  repoSlug: string;
  /** Owner, repo separately (Octokit wants them split). */
  owner: string;
  repo: string;
  /** Pull request number, or `null` if this run wasn't triggered by a PR. */
  prNumber: number | null;
  /** Commit SHA that produced the renders. */
  commitSha: string;
  /** URL of the current workflow run. */
  runUrl: string;
  /** GitHub token to authenticate the REST client. */
  token: string;
}

/**
 * Derive a {@link CommentContext} from the Actions runtime.
 *
 * Pulls the PR number from `github.context.payload.pull_request.number`
 * when present, and falls back to scanning `push` events for an
 * associated PR via the REST API (not done here — out of scope for
 * v0.1; push-event PR lookups would require an extra API call and are
 * rarely what users want when they opt into PR comments).
 */
export function resolveCommentContext(
  token: string,
  contextLike: typeof github.context = github.context
): CommentContext | null {
  if (!token) return null;

  const { owner, repo } = contextLike.repo;
  const prNumber =
    contextLike.payload.pull_request?.number ??
    (typeof contextLike.issue.number === 'number' ? contextLike.issue.number : null);

  const serverUrl = process.env.GITHUB_SERVER_URL || 'https://github.com';
  const runId = process.env.GITHUB_RUN_ID;
  const runUrl = runId ? `${serverUrl}/${owner}/${repo}/actions/runs/${runId}` : '';

  return {
    repoSlug: `${owner}/${repo}`,
    owner,
    repo,
    prNumber: prNumber ?? null,
    commitSha: contextLike.sha,
    runUrl,
    token,
  };
}

/**
 * Post or update the preview comment on the resolved PR.
 *
 * Behavior:
 * - Lists comments on the PR, finds the first one authored by anyone
 *   that contains {@link COMMENT_MARKER}, and PATCHes it.
 * - If no such comment exists, POSTs a new one.
 * - On any API failure, logs a warning via `core.warning` but does NOT
 *   fail the build — rendering already succeeded, so surfacing this as
 *   a hard error would block PRs over a cosmetic problem.
 */
export async function postOrUpdateComment(
  ctx: CommentContext,
  body: string
): Promise<void> {
  if (ctx.prNumber === null) {
    core.info('Skipping PR comment: not triggered by a pull request.');
    return;
  }

  const octokit = github.getOctokit(ctx.token);

  try {
    // Look for an existing comment we own.
    const existing = await octokit.paginate(
      octokit.rest.issues.listComments,
      {
        owner: ctx.owner,
        repo: ctx.repo,
        issue_number: ctx.prNumber,
        per_page: 100,
      }
    );

    const ours = existing.find((c) => typeof c.body === 'string' && c.body.includes(COMMENT_MARKER));

    if (ours) {
      await octokit.rest.issues.updateComment({
        owner: ctx.owner,
        repo: ctx.repo,
        comment_id: ours.id,
        body,
      });
      core.info(`Updated existing preview comment (#${ours.id}).`);
    } else {
      const created = await octokit.rest.issues.createComment({
        owner: ctx.owner,
        repo: ctx.repo,
        issue_number: ctx.prNumber,
        body,
      });
      core.info(`Posted new preview comment (#${created.data.id}).`);
    }
  } catch (err) {
    core.warning(
      `Failed to post preview comment: ${(err as Error).message}. ` +
        'Ensure the workflow has `permissions: pull-requests: write`.'
    );
  }
}
